void test_Signal_Vehicle_State_Mode_normal(void)
{
    uint8 val = 7u;
    Std_ReturnType ret = Com_SendSignal(CVC_COM_SIG_VEHICLE_STATE_MODE, &val);
    TEST_ASSERT_EQUAL_UINT8(E_OK, ret);

    /* Sub-byte: 4 bits at bit 16 (byte 2, shift 0) */
    TEST_ASSERT_EQUAL_HEX8(0x07u, com_tx_pdu_buf[CVC_COM_TX_VEHICLE_STATE][2] & 0x0Fu);
    /* Verify neighboring bits not corrupted */
    TEST_ASSERT_EQUAL_HEX8(0x00u, com_tx_pdu_buf[CVC_COM_TX_VEHICLE_STATE][2] & 0xF0u);
}

